code_changes.content:
[
  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "NilHook.PreApply returns HookActionHalt instead of HookActionContinue. Since NilHook is the base no-op implementation that custom hooks embed, returning Halt here causes ALL apply operations to abort immediately on the PreApply hook. This completely breaks the apply phase. Should return HookActionContinue like all other NilHook methods.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -135,7 +135,7 @@ type NilHook struct{}
 var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 247,
    "severity": "critical",
    "description": "Nil check for input variable config is inverted. Changed from `if config == nil` to `if config != nil`, which means when a variable IS declared in config, an error is thrown. This should error when config IS nil (undeclared variable), not when it's not nil. Input variables that exist will be rejected as undeclared.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -244,7 +244,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	}

 	config := moduleConfig.Module.Variables[addr.Name]
-	if config != nil {
+	if config == nil {
 		var suggestions []string
 		for k := range moduleConfig.Module.Variables {
 			suggestio = append(suggestions, k)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Validate walk check is inverted. The code returns unknown values for NON-validate walks, but the comment and intent state: 'During the validate walk, input variables are always unknown so that we are validating the configuration for all possible input values'. During validate, we SHOULD return unknown. During plan/apply, we should return actual values from NamedValues. This reversal breaks variable resolution during plan and apply operations.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// that are disabled, etc. Terraform's static validation leans towards
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 535,
    "severity": "critical",
    "description": "Unknown instance keys check is inverted. When hasUnknownKeys is FALSE, the code returns DynamicVal, but the comment states 'it means we have an unknown for_each/count' which occurs when hasUnknownKeys is TRUE. The condition should check `if hasUnknownKeys` not `if !hasUnknownKeys`. Deferred resources with unknown counts/for_each will be incorrectly processed.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -532,7 +532,7 @@ func (d *evaluationStateData) GetResource(addr addrs.Resource, rng tfdiags.Sourc
 	// result for _all_ of its work, rather than continuing to duplicate a bunch
 	// of the logic we've tried to encapsulate over ther already.
 	if d.Operation == walkPlan || d.Operation == walkApply {
-		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); !hasUnknownKeys {
+		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); hasUnknownKeys {
 			// There really isn't anything interesting we can do in this situation,
 			// because it means we have an unknown for_each/count, in which case
 			// we can't even predict what the result type will be because it
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Ephemeral mark application is inverted. Changed from `if cfg.Ephemeral` to `if !cfg.Ephemeral`. The comment explicitly states 'An ephemeral input variable always has an ephemeral value inside the module'. If a variable IS ephemeral, it should be marked. Instead, the code now marks NON-ephemeral variables as ephemeral. This causes ephemeral semantics to be applied to regular variables and vice versa—a fundamental data integrity violation that breaks variable isolation.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,7 +189,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *In
 		}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
"
  }
]

